def extract_categories_robust(desc):
    text = desc.strip()
    delimiters = [
        "services in the fields of ",
        "services in ", 
        "services including ", 
        "seeking ", 
        "category of ",
        "categories of ",
        "featuring ",
        "including ",
        "options for "
    ]
    start_index = -1
    used_delimiter = ""
    for d in delimiters:
        idx = text.rfind(d)
        if idx != -1:
            if idx > start_index:
                start_index = idx
                used_delimiter = d
    if start_index == -1:
        return []
    content = text[start_index + len(used_delimiter):]
    if content.startswith("'") and (content.endswith("'") or content.endswith("'.")):
        end_quote = content.rfind("'")
        if end_quote > 0:
            content = content[1:end_quote]
    if content.endswith('.'):
        content = content[:-1]
    parts = [p.strip() for p in content.split(',')]
    cats = []
    for p in parts:
        subparts = p.split(' and ')
        for sp in subparts:
            sp = sp.strip()
            if not sp: continue
            if sp[0].islower() and sp not in ['of', 'the']: continue
            cats.append(sp)
    return cats

